INSERT INTO `v1_cbca4c68900b058be7859053fc86c90e111abe8bdc159a63d8dec7a6f4d760ee` VALUES ("リリ", 0, 1, 321, 40011, 2, "もうすぐ、みなさまに\nお会いできるのですね。\n胸が高鳴ってしまいます……\n", 1, 1, 24001, 125801);
INSERT INTO `v1_cbca4c68900b058be7859053fc86c90e111abe8bdc159a63d8dec7a6f4d760ee` VALUES ("クリア", 0, 1, 322, 40011, 2, "初めまして、クリアです♪\nみなさんと一緒に冒険するの\nとっても楽しみにしてます", 1, 2, 24001, 126001);
INSERT INTO `v1_cbca4c68900b058be7859053fc86c90e111abe8bdc159a63d8dec7a6f4d760ee` VALUES ("プレシア", 0, 1, 323, 40011, 2, "んーと。\nこれ、あげる。\nはい", 1, 3, 24001, 126101);
INSERT INTO `v1_cbca4c68900b058be7859053fc86c90e111abe8bdc159a63d8dec7a6f4d760ee` VALUES ("リリ", 0, 1, 324, 40011, 2, "あらためまして……\n【アルターメイデン】の\nギルドマスター、リリと申します", 2, 4, 24001, 125801);
INSERT INTO `v1_cbca4c68900b058be7859053fc86c90e111abe8bdc159a63d8dec7a6f4d760ee` VALUES ("クリア", 0, 1, 325, 40011, 2, "こんにちは、お兄さん♪\n【アルターメイデン】の\nクリアです", 2, 5, 24001, 126001);
INSERT INTO `v1_cbca4c68900b058be7859053fc86c90e111abe8bdc159a63d8dec7a6f4d760ee` VALUES ("プレシア", 0, 1, 326, 40011, 2, "お兄。\nきてくれて、うれしい", 2, 6, 24001, 126101);
